mod repro_tests {
    use lopdf::Document;

    #[test]
    fn test_header_with_binary_bytes() {
        // Header with binary bytes after the version number (like ImageMill produces)
        let pdf_data = b"%PDF-1.3 \xb0\x9f\x92\x9c\x9f\xd4\xe0\xce\xd0\xd0\xd0\r\n%%EOF\n";
        let result = Document::load_mem(&pdf_data[..]);
        match result {
            Ok(doc) => assert_eq!(doc.version, "1.3"),
            Err(e) => panic!("Failed to parse header with binary bytes: {}", e),
        }
    }

