    fn test_header_with_binary_bytes_no_eol() {
        // Header with binary bytes but no EOL - should still fail since no newline
        // Actually this is the problematic case from the issue
        let pdf_data = b"%PDF-1.3 \xb0\x9f\x92\x9c\x9f\xd4\xe0\xce\xd0\xd0\xd0\r";
        // This should still fail because there's not enough content after header
        // The key test is the one above
    }
}
